1240	TEST_CASE( "npc_camp_water_through_stomach", "[npc][needs][camp]" )
1241	{
1242	    clear_avatar();
1243	    clear_map_without_vision();
1244	    get_player_character().camps.clear();
1245	    map &m = get_map();
1246	    // Use mid-map position so NPC and camp share the same OMT regardless
1247	    // of where the map's absolute origin falls.
1248	    const tripoint_bub_ms mid{ MAPSIZE_X / 2, MAPSIZE_Y / 2, 0 };
1249	    const tripoint_abs_ms zone_loc = m.get_abs( mid );
1250	    REQUIRE( m.inbounds( zone_loc ) );
1251	    mapgen_place_zone( zone_loc, zone_loc, zone_type_CAMP_FOOD, your_fac, {}, "food" );
1252	    mapgen_place_zone( zone_loc, zone_loc, zone_type_CAMP_STORAGE, your_fac, {}, "storage" );
1253	    faction *camp_faction = get_player_character().get_faction();
1254	    const tripoint_abs_omt this_omt = project_to<coords::omt>( zone_loc );
1255	    m.add_camp( this_omt, "faction_camp" );
1256	    std::optional<basecamp *> bcp = overmap_buffer.find_camp( this_omt.xy() );
1257	    REQUIRE( !!bcp );
1258	    basecamp *test_camp = *bcp;
1259	    test_camp->define_camp( this_omt, "faction_base_bare_bones_NPC_camp_0", false );
1260	    test_camp->set_owner( your_fac );
1261	    REQUIRE( test_camp->has_water() );
1262	
1263	    // Spawn NPC at mid-map so it's in the same OMT as the camp
1264	    npc &guy = spawn_npc( mid.xy(), "test_talker" );
1265	    clear_character( guy, true );
1266	    guy.set_fac( faction_your_followers );
1267	    guy.stomach.empty();
1268	    guy.guts.empty();
1269	    guy.set_hunger( 0 );
1270	    camp_faction->empty_food_supply();
1271	
1272	    SECTION( "camp water enters stomach, NPC-facing thirst drops" ) {
1273	        guy.set_thirst( 200 );
1274	        REQUIRE( guy.get_thirst() > 40 );
1275	
1276	        CHECK( guy.consume_food_from_camp() );
1277	        CHECK( guy.stomach.get_water() > 0_ml );
1278	        CHECK( guy.get_thirst() < 200 );
1279	    }
1280	
1281	    SECTION( "intake capped at stomach capacity" ) {
1282	        // Pre-fill stomach near capacity, leaving only 50ml room
1283	        const units::volume room = guy.stomach.stomach_remaining( guy );
1284	        if( room > 50_ml ) {
1285	            guy.stomach.ingest( { room - 50_ml, 0_ml, {} } );
1286	        }
1287	        guy.set_thirst( 800 );
1288	
1289	        guy.consume_food_from_camp();
1290	
1291	        CHECK( guy.stomach.contains() <= guy.stomach.capacity( guy ) );
1292	    }
1293	
