1295	        // Fill stomach to capacity
1296	        const units::volume room = guy.stomach.stomach_remaining( guy );
1297	        guy.stomach.ingest( { room, 0_ml, {} } );
1298	        // Raw thirst must exceed 40 + capacity/5 so NPC-facing thirst
1299	        // still passes the > 40 gate despite stomach water subtraction.
