            CHECK( guy.get_part_temp_conv( bp ) == BODYTEMP_NORM );
        }
    }

    SECTION( "bodytemp decreases after 10-second boundary in freezing weather" ) {
        calendar::turn = calendar::turn_zero + 10_seconds;
        npc &guy = spawn_npc( { 50, 50 }, "test_talker" );
