TEST_CASE( "camp_resident_guard_transitions", "[npc][camp]" )
{
    clear_map_without_vision();
    clear_avatar();
    map &here = get_map();
    npc &guy = spawn_npc( { 50, 50 }, "test_talker" );
    clear_character( guy, true );
