        clear_character( guy, true );
        guy.set_all_parts_temp_conv( BODYTEMP_NORM );
        guy.set_all_parts_temp_cur( BODYTEMP_NORM );

        on_load_test( guy, 0_seconds, 30_minutes );

        bool any_cooled = false;
