TEST_CASE( "npc_address_needs_ground_water", "[npc][needs]" )
{
    clear_map_without_vision();
    clear_avatar();
    get_player_character().camps.clear();
    set_time_to_day();
    npc &guy = spawn_npc( { 50, 50 }, "test_talker" );
