    guy.set_hunger( -1 );
    guy.set_thirst( 0 );
    m.build_map_cache( 0 );

    // Camp food is in the candidate list.
    auto cands = guy.find_food_candidates();
    bool has_camp = false;
    for( const npc_short_term_cache::need_candidate &c : cands ) {
        if( c.source_kind == npc::need_source::camp_food ) {
            has_camp = true;
        }
