    guy.set_attitude( NPCATT_FOLLOW );
    guy.set_stored_kcal( 1000 );
    guy.set_hunger( 300 );
    guy.set_thirst( 0 );
    guy.worn.wear_item( guy, item( itype_backpack ), false, false );
    REQUIRE( guy.has_calorie_deficit() );

