        guy.set_committed_goal( "camp_work" );
        guy.set_moves( 200 );
        const int moves_before = guy.get_moves();
        iexamine_helper::handle_harvest( guy, itype_sandwich_cheese_grilled, false );

        CHECK( guy.get_moves() == moves_before );
    }
}

