        guy.add_effect( effect_lying_down, 30_minutes, false, 1, false, true );
        REQUIRE( guy.has_effect( effect_lying_down ) );

        guy.clear_committed_goal();

        CHECK( guy.has_effect( effect_lying_down ) );
    }
}

