+TEST_CASE( "npc_camp_resident_downtime_uses_chairs_in_current_tile", "[npc][camp]" )
+{
+    clear_avatar();
+    clear_map_without_vision();
+    get_player_character().camps.clear();
+    map &m = get_map();
+
+    const tripoint_bub_ms camp_pos{ MAPSIZE_X / 2, MAPSIZE_Y / 2, 0 };
+    const tripoint_abs_ms camp_abs = m.get_abs( camp_pos );
+    REQUIRE( m.inbounds( camp_abs ) );
+    const tripoint_abs_omt camp_omt = project_to<coords::omt>( camp_abs );
+
+    m.add_camp( camp_omt, "faction_camp" );
+    std::optional<basecamp *> bcp = overmap_buffer.find_camp( camp_omt.xy() );
+    REQUIRE( !!bcp );
+    basecamp *test_camp = *bcp;
+    test_camp->define_camp( camp_omt, "faction_base_bare_bones_NPC_camp_0", false );
+    test_camp->set_owner( your_fac );
+
+    const tripoint_abs_omt expansion_omt = camp_omt + point::east;
+    test_camp->add_expansion( "faction_base_bare_bones_NPC_camp_0", expansion_omt );
+    REQUIRE( test_camp->point_within_camp( expansion_omt ) );
+
+    const tripoint_bub_ms original_seat = camp_pos + tripoint_rel_ms{ 1, 0, 0 };
+    const tripoint_abs_ms original_seat_abs = m.get_abs( original_seat );
+    REQUIRE( project_to<coords::omt>( original_seat_abs ) == camp_omt );
+    m.furn_set( original_seat, furn_f_armchair );
+
+    const tripoint_bub_ms expansion_seat = m.get_bub( project_combine( expansion_omt, point_omt_ms{ 1, 1 } ) );
+    REQUIRE( m.inbounds( expansion_seat ) );
+    REQUIRE( project_to<coords::omt>( m.get_abs( expansion_seat ) ) == expansion_omt );
+    m.furn_set( expansion_seat, furn_f_armchair );
+    m.build_map_cache( 0 );
+
+    npc &guy = spawn_npc( camp_pos.xy(), "test_talker" );
+    clear_character( guy, true );
+    guy.set_fac( faction_your_followers );
+    guy.assigned_camp = camp_omt;
+    guy.set_mission( NPC_MISSION_CAMP_RESIDENT );
+    guy.set_attitude( NPCATT_NULL );
+
+    // Simulate the post-expansion displacement/reassignment case: the NPC is
+    // still in the original camp tile, but has a stale downtime seat in an
+    // expansion tile.  Downtime should pick a seat in the current OMT instead
+    // of walking back and forth between camp tiles.
+    guy.chair_pos = m.get_abs( expansion_seat );
+    guy.worker_downtime();
+
+    REQUIRE( guy.chair_pos );
+    CHECK( *guy.chair_pos == original_seat_abs );
+    CHECK( project_to<coords::omt>( *guy.chair_pos ) == camp_omt );
+    overmap_buffer.clear_camps( camp_omt.xy() );
+}
+
